request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?modelName
  ?choreo
  ?task
  ?taskName
  ?participantName
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:belongsTo ?org ;
         tai:normalizedId ?mid .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo ;
               bbo:name ?participantName .

  FILTER(CONTAINS(LCASE(STR(?participantName)), LCASE("airline")))
}
ORDER BY ?modelName ?choreo ?taskName ?participantName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?modelName
  ?choreo
  ?participant
  ?participantName
  ?task
  ?taskName
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .

  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:belongsTo ?org ;
         tai:normalizedId ?mid .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo ;
               bbo:name ?participantName .

  FILTER(
    CONTAINS(LCASE(STR(?participantName)), LCASE("airline")) ||
    CONTAINS(LCASE(STR(?participantName)), LCASE("airlines"))
  )

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  OPTIONAL {
    ?task bboExt:initiatingParticipantRef ?partRef .
    FILTER(STRENDS(STR(?participant), ?partRef))
  }
}
ORDER BY ?modelName ?choreo ?taskName ?participantName
LIMIT 25

